```class Solution {
public:
    int wordCount(vector<string>& startWords, vector<string>& targetWords) {
        unordered_map<string, int> start;
        for (string& s : startWords) {
            sort(s.begin(), s.end());
            start[s]++;
        }
        int res = 0;
        for (string& t : targetWords) {
            for (char c = 'a'; c <= 'z'; c++) {
                string temp = t;
                temp += c;
                sort(temp.begin(), temp.end());
                if (start.count(temp)) res++;
                break;
            }
        }
        return res;
    }
};
